\tzpsection{Derivation Layer}
\begingroup\small
\paragraph{Continuity Constraint.}
\begin{equation}
\partial_r(rv_r)+\partial_z(zv_z)=0.
\end{equation}

\paragraph{Resonance Operator.}
\begin{equation}
\mathcal{R}_{\mathrm{EHD}}[\mathbf{v}]
=
-\frac{\nabla p}{\rho}
+
\frac{q}{m}
(\mathbf{E}+\mathbf{v}\times\mathbf{B}).
\end{equation}

\paragraph{Mode Selection.}
\begin{equation}
\mathcal{R}_{\mathrm{EHD}}[\mathbf{v}_k]
=
\lambda_k\mathbf{v}_k.
\end{equation}

\paragraph{Primary Derivation.}
The admissible axisymmetric flow space is constrained by:
\begin{equation}
\partial_r(rv_r)+\partial_z(zv_z)=0.
\end{equation}

Pressure and electromagnetic forcing define the total acceleration operator:
\begin{equation}
\mathcal{R}_{\mathrm{EHD}}[\mathbf{v}]
=
-\frac{\nabla p}{\rho}
+
\frac{q}{m}
(\mathbf{E}+\mathbf{v}\times\mathbf{B}).
\end{equation}

Resonant modes are those reproduced by the operator up to scale:
\begin{equation}
\boxed{
\mathcal{R}_{\mathrm{EHD}}[\mathbf{v}_k]
=
\lambda_k\mathbf{v}_k.
}
\end{equation}

\paragraph{Wolfram Form.}
\begin{verbatim}
D[r*vr[r,z], r] + D[z*vz[r,z], z] == 0
REHD[v_] := -Grad[p]/rho + (q/m)*(E + Cross[v, B])
REHD[v[k]] == lambda[k]*v[k]
\end{verbatim}

\paragraph{Interpretation.}
The EHD resonance operator identifies flow modes amplified by pressure and electromagnetic forcing.
\endgroup
